<?php
namespace NYforms;
defined( 'ABSPATH' ) || exit;

class Rest {
	public function hooks() { add_action( 'rest_api_init', array( $this, 'routes' ) ); }
	public function routes() {
		$this->route( '/forms', array( 'GET' => 'forms', 'POST' => 'create' ), 'manage' );
		$this->route( '/forms/import', array( 'POST' => 'import' ), 'manage' );
		$this->route( '/forms/(?P<id>\d+)', array( 'GET' => 'form', 'PATCH' => 'update', 'PUT' => 'update', 'DELETE' => 'trash_form' ), 'manage' );
		$this->route( '/forms/(?P<id>\d+)/status', array( 'PATCH' => 'form_status' ), 'manage' );
		$this->route( '/forms/(?P<id>\d+)/duplicate', array( 'POST' => 'duplicate' ), 'manage' );
		$this->route( '/forms/(?P<id>\d+)/export', array( 'GET' => 'export' ), 'manage' );
		$this->route( '/forms/(?P<form_id>\d+)/entries', array( 'GET' => 'entries', 'POST' => 'create_entry' ), 'entries_permission' );
		$this->route( '/forms/(?P<form_id>\d+)/entries/export', array( 'GET' => 'entries_export' ), 'export_permission' );
		$this->route( '/entries/(?P<id>\d+)', array( 'GET' => 'entry', 'PATCH' => 'update_entry', 'PUT' => 'update_entry', 'DELETE' => 'delete_entry' ), 'entries_permission' );
		$this->route( '/entries/(?P<id>\d+)/files', array( 'GET' => 'entry_files' ), 'entries_permission' );
		$this->route( '/files/(?P<id>\d+)/download', array( 'GET' => 'download_file' ), 'entries_permission' );
		$this->route( '/settings', array( 'GET' => 'settings', 'PATCH' => 'update_settings', 'PUT' => 'update_settings' ), 'manage' );
		$this->route( '/system-report', array( 'GET' => 'system_report' ), 'manage' );
		$this->route( '/events', array( 'GET' => 'events' ), 'manage' );
		$this->route( '/openapi', array( 'GET' => 'openapi' ), 'manage' );
		register_rest_route( 'nyforms/v1', '/privacy/requests', array( 'methods' => \WP_REST_Server::CREATABLE, 'callback' => array( $this, 'privacy_request' ), 'permission_callback' => '__return_true' ) );
	}
	private function route( $path, $methods, $permission ) { $routes = array(); foreach ( $methods as $method => $callback ) { $routes[] = array( 'methods' => $method, 'callback' => array( $this, $callback ), 'permission_callback' => array( $this, $permission ) ); } register_rest_route( 'nyforms/v1', $path, $routes ); }
	public function manage( $request ) { return $this->allowed( $request, 'nyforms_manage_forms' ); }
	public function entries_permission( $request ) { return $this->allowed( $request, 'nyforms_view_entries' ); }
	public function export_permission( $request ) { return $this->allowed( $request, 'nyforms_export_entries' ); }
	private function allowed( $request, $capability ) { if ( ! current_user_can( $capability ) ) { return false; } $nonce = $request instanceof \WP_REST_Request ? $request->get_header( 'X-WP-Nonce' ) : ''; if ( $nonce && wp_verify_nonce( $nonce, 'wp_rest' ) ) { return true; } $settings = get_option( 'nyforms_settings', array() ); return ! empty( $settings['rest_api_enabled'] ) && is_ssl(); }
	private function repo() { return Plugin::instance()->repository; }
	private function audit( $type, $form_id = 0, $entry_id = 0, $context = array() ) { $context['actor'] = get_current_user_id(); $context['via'] = 'rest'; $this->repo()->event( $type, $form_id, $entry_id, $context ); }
	private function paged( $request, $total, $items ) { $page = max( 1, absint( $request->get_param( 'page' ) ?: 1 ) ); $per_page = min( 100, max( 1, absint( $request->get_param( 'per_page' ) ?: 20 ) ) ); $response = rest_ensure_response( $items ); $response->header( 'X-WP-Total', (int) $total ); $response->header( 'X-WP-TotalPages', (int) max( 1, ceil( $total / $per_page ) ) ); return $response; }
	public function forms( $request ) { $page = max( 1, absint( $request['page'] ?: 1 ) ); $per_page = min( 100, max( 1, absint( $request['per_page'] ?: 20 ) ) ); $status = sanitize_key( $request['status'] ?? '' ); $status = in_array( $status, array( '', 'active', 'draft', 'inactive', 'trash' ), true ) ? $status : ''; $query = array( 'search' => sanitize_text_field( $request['search'] ?? '' ), 'status' => $status, 'page' => $page, 'per_page' => $per_page, 'orderby' => sanitize_key( $request['orderby'] ?? 'updated_at' ), 'order' => strtoupper( $request['order'] ?? 'DESC' ) ); return $this->paged( $request, $this->repo()->forms_count( $query ), $this->repo()->forms_api( $query ) ); }
	public function form( $request ) { return $this->respond_form( $request['id'] ); }
	public function create( $request ) { $id = $this->repo()->create_form( $request->get_json_params() ); if ( is_wp_error( $id ) ) { return $this->client_error( $id ); } $this->audit( 'form.created', $id ); return $this->respond_form( $id, 201 ); }
	public function update( $request ) { $form = $this->repo()->update_form( $request['id'], $request->get_json_params() ); if ( is_wp_error( $form ) ) { return $this->client_error( $form ); } $this->audit( 'form.updated', $form['id'] ); return rest_ensure_response( $form ); }
	public function trash_form( $request ) { return $this->change_form_status( $request['id'], 'trash' ); }
	public function form_status( $request ) { $status = sanitize_key( $request['status'] ?? '' ); if ( ! in_array( $status, array( 'active', 'draft', 'inactive', 'trash' ), true ) ) { return new \WP_Error( 'nyforms_invalid_status', __( 'Unsupported form status.', 'nyforms' ), array( 'status' => 400 ) ); } return $this->change_form_status( $request['id'], $status ); }
	private function change_form_status( $id, $status ) { if ( ! $this->repo()->set_form_status( $id, $status ) ) { return new \WP_Error( 'nyforms_not_found', __( 'Form not found.', 'nyforms' ), array( 'status' => 404 ) ); } $this->audit( 'form.status_changed', $id, 0, array( 'status' => $status ) ); return $this->respond_form( $id ); }
	public function duplicate( $request ) { $id = $this->repo()->duplicate( $request['id'] ); if ( is_wp_error( $id ) ) { return $this->client_error( $id ); } $this->audit( 'form.duplicated', $id, 0, array( 'source_form_id' => absint( $request['id'] ) ) ); return $this->respond_form( $id, 201 ); }
	public function export( $request ) { $form = $this->repo()->form( $request['id'] ); return $form ? rest_ensure_response( array( 'nyforms_format' => 1, 'exported_at' => gmdate( 'c' ), 'form' => $form['definition'] ) ) : new \WP_Error( 'nyforms_not_found', __( 'Form not found.', 'nyforms' ), array( 'status' => 404 ) ); }
	public function import( $request ) { $payload = $request->get_json_params(); if ( ! is_array( $payload ) || 1 !== absint( $payload['nyforms_format'] ?? 0 ) || empty( $payload['form'] ) ) { return new \WP_Error( 'nyforms_invalid_import', __( 'This is not a supported NYforms export.', 'nyforms' ), array( 'status' => 400 ) ); } $id = $this->repo()->create_form( $payload['form'] ); if ( is_wp_error( $id ) ) { return $this->client_error( $id ); } $this->audit( 'form.imported', $id ); return $this->respond_form( $id, 201 ); }
	public function entries( $request ) { $form = $this->repo()->form( $request['form_id'] ); if ( ! $form ) { return new \WP_Error( 'nyforms_not_found', __( 'Form not found.', 'nyforms' ), array( 'status' => 404 ) ); } $query = $this->entry_query( $request ); return $this->paged( $request, $this->repo()->entries_count_api( $request['form_id'], $query ), $this->repo()->entries_api( $request['form_id'], $query ) ); }
	private function entry_query( $request ) { $status = sanitize_key( $request['status'] ?? 'active' ); if ( ! in_array( $status, array( 'all', 'active', 'spam', 'trashed', 'unread', 'starred' ), true ) ) { $status = 'active'; } return array( 'status' => $status, 'search' => sanitize_text_field( $request['search'] ?? '' ), 'field' => sanitize_key( $request['field'] ?? '' ), 'after' => sanitize_text_field( $request['after'] ?? '' ), 'before' => sanitize_text_field( $request['before'] ?? '' ), 'page' => max( 1, absint( $request['page'] ?: 1 ) ), 'per_page' => min( 100, max( 1, absint( $request['per_page'] ?: 20 ) ) ), 'orderby' => sanitize_key( $request['orderby'] ?? 'submitted_at' ), 'order' => strtoupper( $request['order'] ?? 'DESC' ) ); }
	public function create_entry( $request ) { if ( ! current_user_can( 'nyforms_manage_entries' ) ) { return new \WP_Error( 'nyforms_forbidden', __( 'You are not allowed to create entries.', 'nyforms' ), array( 'status' => 403 ) ); } $form = $this->repo()->form( $request['form_id'] ); if ( ! $form ) { return new \WP_Error( 'nyforms_not_found', __( 'Form not found.', 'nyforms' ), array( 'status' => 404 ) ); } $raw = (array) $request->get_param( 'values' ); $values = array(); foreach ( $form['definition']['fields'] as $field ) { if ( in_array( $field['type'], array( 'html', 'section', 'page', 'file', 'total', 'calculation' ), true ) ) { continue; } $valid = Fields::validate( $field, $raw[ $field['key'] ] ?? '' ); if ( is_wp_error( $valid ) ) { return $this->client_error( $valid ); } $values[ $field['key'] ] = $valid; } $id = $this->repo()->create_entry( $form, $values, hash_hmac( 'sha256', 'api|' . wp_json_encode( $values ), wp_salt( 'nonce' ) ) ); $this->audit( 'entry.created', $form['id'], $id ); return new \WP_REST_Response( $this->repo()->entry( $id ), 201 ); }
	public function entry( $request ) { $entry = $this->repo()->entry( $request['id'] ); if ( ! $entry ) { return new \WP_Error( 'nyforms_not_found', __( 'Entry not found.', 'nyforms' ), array( 'status' => 404 ) ); } $this->repo()->update_entry_status( $entry['id'], $entry['status'], true ); return rest_ensure_response( $this->repo()->entry( $entry['id'] ) ); }
	public function update_entry( $request ) { if ( ! current_user_can( 'nyforms_manage_entries' ) ) { return new \WP_Error( 'nyforms_forbidden', __( 'You are not allowed to manage entries.', 'nyforms' ), array( 'status' => 403 ) ); } $entry = $this->repo()->entry( $request['id'] ); if ( ! $entry ) { return new \WP_Error( 'nyforms_not_found', __( 'Entry not found.', 'nyforms' ), array( 'status' => 404 ) ); } $status = sanitize_key( $request['status'] ?? $entry['status'] ); if ( ! in_array( $status, array( 'active', 'spam', 'trashed' ), true ) ) { return new \WP_Error( 'nyforms_invalid_status', __( 'Unsupported entry status.', 'nyforms' ), array( 'status' => 400 ) ); } $this->repo()->update_entry_status( $entry['id'], $status, $request->has_param( 'is_read' ) ? rest_sanitize_boolean( $request['is_read'] ) : null ); if ( $request->has_param( 'is_starred' ) ) { $this->repo()->update_entry_starred( $entry['id'], rest_sanitize_boolean( $request['is_starred'] ) ); } $this->audit( 'entry.updated', $entry['form_id'], $entry['id'], array( 'status' => $status ) ); return rest_ensure_response( $this->repo()->entry( $entry['id'] ) ); }
	public function delete_entry( $request ) { if ( ! current_user_can( 'nyforms_manage_entries' ) ) { return new \WP_Error( 'nyforms_forbidden', __( 'You are not allowed to delete entries.', 'nyforms' ), array( 'status' => 403 ) ); } $entry = $this->repo()->entry( $request['id'] ); if ( ! $entry || ! $this->repo()->delete_entry( $request['id'] ) ) { return new \WP_Error( 'nyforms_not_found', __( 'Entry not found.', 'nyforms' ), array( 'status' => 404 ) ); } $this->audit( 'entry.deleted', $entry['form_id'], $entry['id'] ); return new \WP_REST_Response( null, 204 ); }
	public function entry_files( $request ) { $entry = $this->repo()->entry( $request['id'] ); return $entry ? rest_ensure_response( $this->repo()->files_for_entry( $entry['id'] ) ) : new \WP_Error( 'nyforms_not_found', __( 'Entry not found.', 'nyforms' ), array( 'status' => 404 ) ); }
	public function download_file( $request ) { $file = $this->repo()->file( $request['id'] ); $path = $file ? get_attached_file( absint( $file['attachment_id'] ) ) : false; if ( ! $file || ! $path || ! file_exists( $path ) ) { return new \WP_Error( 'nyforms_not_found', __( 'File not found.', 'nyforms' ), array( 'status' => 404 ) ); } nocache_headers(); header( 'Content-Type: ' . sanitize_mime_type( $file['mime_type'] ) ); header( 'Content-Disposition: attachment; filename="' . sanitize_file_name( $file['original_name'] ) . '"' ); header( 'Content-Length: ' . filesize( $path ) ); readfile( $path ); exit; }
	public function entries_export( $request ) { $format = sanitize_key( $request['format'] ?? 'json' ); if ( 'csv' !== $format ) { return $this->entries( $request ); } $form = $this->repo()->form( $request['form_id'] ); if ( ! $form ) { return new \WP_Error( 'nyforms_not_found', __( 'Form not found.', 'nyforms' ), array( 'status' => 404 ) ); } $rows = $this->repo()->entries_api( $form['id'], array_merge( $this->entry_query( $request ), array( 'page' => 1, 'per_page' => 1000 ) ) ); $headers = array( 'entry_id', 'submitted_at', 'status' ); foreach ( $form['definition']['fields'] as $field ) { if ( ! in_array( $field['type'], array( 'html', 'section', 'page' ), true ) ) { $headers[] = $field['key']; } } nocache_headers(); header( 'Content-Type: text/csv; charset=utf-8' ); header( 'Content-Disposition: attachment; filename="nyforms-' . absint( $form['id'] ) . '-entries.csv"' ); $out = fopen( 'php://output', 'w' ); fputcsv( $out, $headers ); foreach ( $rows as $entry ) { $row = array( $entry['id'], $entry['submitted_at'], $entry['status'] ); foreach ( array_slice( $headers, 3 ) as $key ) { $value = $entry['values'][ $key ] ?? ''; $value = is_array( $value ) ? implode( ', ', $value ) : (string) $value; $row[] = preg_match( '/^[=+\-@]/', $value ) ? "'" . $value : $value; } fputcsv( $out, $row ); } fclose( $out ); exit; }
	public function settings() { return rest_ensure_response( $this->safe_settings() ); }
	public function update_settings( $request ) { $settings = wp_parse_args( get_option( 'nyforms_settings', array() ), array( 'rate_limit' => 10, 'retention_days' => 0, 'delete_data_on_uninstall' => false, 'data_collection' => false, 'recaptcha_enabled' => false, 'recaptcha_site_key' => '', 'recaptcha_secret_key' => '', 'recaptcha_type' => 'checkbox', 'rest_api_enabled' => false ) ); foreach ( array( 'rate_limit', 'retention_days', 'data_collection', 'delete_data_on_uninstall', 'recaptcha_enabled', 'recaptcha_site_key', 'recaptcha_type', 'rest_api_enabled' ) as $key ) { if ( $request->has_param( $key ) ) { $settings[ $key ] = $request->get_param( $key ); } } if ( $request->has_param( 'recaptcha_secret_key' ) ) { $settings['recaptcha_secret_key'] = sanitize_text_field( $request['recaptcha_secret_key'] ); } $settings['rate_limit'] = min( 1000, max( 1, absint( $settings['rate_limit'] ) ) ); $settings['retention_days'] = absint( $settings['retention_days'] ); foreach ( array( 'data_collection', 'delete_data_on_uninstall', 'recaptcha_enabled', 'rest_api_enabled' ) as $key ) { $settings[ $key ] = rest_sanitize_boolean( $settings[ $key ] ); } $settings['recaptcha_site_key'] = sanitize_text_field( $settings['recaptcha_site_key'] ); $settings['recaptcha_type'] = in_array( $settings['recaptcha_type'], array( 'checkbox', 'invisible' ), true ) ? $settings['recaptcha_type'] : 'checkbox'; update_option( 'nyforms_settings', $settings ); $this->audit( 'settings.updated' ); return rest_ensure_response( $this->safe_settings() ); }
	private function safe_settings() { $settings = get_option( 'nyforms_settings', array() ); unset( $settings['recaptcha_secret_key'] ); $settings['recaptcha_secret_configured'] = ! empty( get_option( 'nyforms_settings', array() )['recaptcha_secret_key'] ); return $settings; }
	public function system_report() { return rest_ensure_response( array( 'plugin_version' => NYFORMS_VERSION, 'database_version' => get_option( 'nyforms_db_version' ), 'rest_url' => rest_url( 'nyforms/v1/' ), 'wordpress_version' => get_bloginfo( 'version' ), 'php_version' => PHP_VERSION ) ); }
	public function events( $request ) { return $this->paged( $request, $this->repo()->events_count(), $this->repo()->events( max( 1, absint( $request['page'] ?: 1 ) ), min( 100, max( 1, absint( $request['per_page'] ?: 20 ) ) ) ) ); }
	public function openapi() { $secure = array( 'security' => array( array( 'wordpressAuth' => array() ) ) ); return rest_ensure_response( array( 'openapi' => '3.0.3', 'info' => array( 'title' => 'NYforms API', 'version' => 'v1', 'description' => __( 'Authenticated WordPress admin integration API. External access requires HTTPS and the NYforms REST API setting. Cookie requests use X-WP-Nonce; remote integrations use WordPress Application Passwords.', 'nyforms' ) ), 'servers' => array( array( 'url' => rest_url( 'nyforms/v1/' ) ) ), 'components' => array( 'securitySchemes' => array( 'wordpressAuth' => array( 'type' => 'http', 'scheme' => 'basic', 'description' => __( 'WordPress Application Password over HTTPS, or a logged-in cookie with X-WP-Nonce.', 'nyforms' ) ) ) ), 'paths' => array( '/forms' => array( 'get' => array_merge( array( 'summary' => __( 'List forms', 'nyforms' ) ), $secure ), 'post' => array_merge( array( 'summary' => __( 'Create a form', 'nyforms' ) ), $secure ) ), '/forms/{id}' => array( 'get' => array_merge( array( 'summary' => __( 'Read a form', 'nyforms' ) ), $secure ), 'patch' => array_merge( array( 'summary' => __( 'Update a form', 'nyforms' ) ), $secure ), 'delete' => array_merge( array( 'summary' => __( 'Move a form to trash', 'nyforms' ) ), $secure ) ), '/forms/{id}/duplicate' => array( 'post' => array_merge( array( 'summary' => __( 'Duplicate a form', 'nyforms' ) ), $secure ) ), '/forms/{id}/export' => array( 'get' => array_merge( array( 'summary' => __( 'Export a versioned JSON form definition', 'nyforms' ) ), $secure ) ), '/forms/import' => array( 'post' => array_merge( array( 'summary' => __( 'Import a versioned JSON form definition', 'nyforms' ) ), $secure ) ), '/forms/{form_id}/entries' => array( 'get' => array_merge( array( 'summary' => __( 'List entries', 'nyforms' ) ), $secure ), 'post' => array_merge( array( 'summary' => __( 'Create an authenticated entry', 'nyforms' ) ), $secure ) ), '/forms/{form_id}/entries/export' => array( 'get' => array_merge( array( 'summary' => __( 'Export entries as paginated JSON or synchronous CSV', 'nyforms' ) ), $secure ) ), '/entries/{id}' => array( 'get' => array_merge( array( 'summary' => __( 'Read an entry', 'nyforms' ) ), $secure ), 'patch' => array_merge( array( 'summary' => __( 'Update entry state', 'nyforms' ) ), $secure ), 'delete' => array_merge( array( 'summary' => __( 'Permanently delete an entry', 'nyforms' ) ), $secure ) ), '/entries/{id}/files' => array( 'get' => array_merge( array( 'summary' => __( 'List entry file metadata', 'nyforms' ) ), $secure ) ), '/files/{id}/download' => array( 'get' => array_merge( array( 'summary' => __( 'Download an authorized entry file', 'nyforms' ) ), $secure ) ), '/settings' => array( 'get' => array_merge( array( 'summary' => __( 'Read safe settings; secrets are redacted', 'nyforms' ) ), $secure ), 'patch' => array_merge( array( 'summary' => __( 'Update settings', 'nyforms' ) ), $secure ) ), '/system-report' => array( 'get' => array_merge( array( 'summary' => __( 'Read live diagnostics', 'nyforms' ) ), $secure ) ), '/events' => array( 'get' => array_merge( array( 'summary' => __( 'List mutation audit events without entry values', 'nyforms' ) ), $secure ) ), '/privacy/requests' => array( 'post' => array( 'summary' => __( 'Initiate a confirmed WordPress privacy request', 'nyforms' ), 'security' => array(), 'description' => __( 'Public, generic 202 response. Rate limited and optionally protected by reCAPTCHA.', 'nyforms' ) ) ) ) ) ); }
	public function privacy_request( $request ) { $email = sanitize_email( $request['email'] ?? '' ); $type = sanitize_key( $request['type'] ?? '' ); if ( ! is_email( $email ) || ! in_array( $type, array( 'export', 'erase' ), true ) || ! Privacy::public_request_allowed( $request ) ) { return new \WP_REST_Response( array( 'message' => __( 'If the request can be processed, you will receive a confirmation email.', 'nyforms' ) ), 202 ); } $result = Privacy::create_request( $email, $type ); return new \WP_REST_Response( array( 'message' => __( 'If the request can be processed, you will receive a confirmation email.', 'nyforms' ), 'request_created' => ! is_wp_error( $result ) ), 202 ); }
	private function client_error( $error ) { $data = $error->get_error_data(); if ( ! is_array( $data ) || empty( $data['status'] ) ) { $error->add_data( array( 'status' => 400 ) ); } return $error; }
	private function respond_form( $id, $status = 200 ) { $form = $this->repo()->form( $id ); return $form ? new \WP_REST_Response( $form, $status ) : new \WP_Error( 'nyforms_not_found', __( 'Form not found.', 'nyforms' ), array( 'status' => 404 ) ); }
}
